        url: `https://github.com/acme/brain/commit/${sha}`,
        author: { name: "Marcus", email: "marcus@test.com" },
      }],
    });

    await fetch(
      `${baseUrl}/api/workspaces/${workspace.workspaceId}/webhooks/github`,
